const ENCRYPTED_PAYLOAD = {"kdf": "PBKDF2-SHA256", "iterations": 250000, "salt": "qzts+FGXOET6CFnTwZ0UrQ==", "nonce": "Jy/IubNV1wYwWvws", "ciphertext": ""};

const form = document.getElementById("password-form");
const passwordInput = document.getElementById("password");
const statusEl = document.getElementById("status");
const gate = document.getElementById("gate");
const app = document.getElementById("app");
const content = document.getElementById("content");
const search = document.getElementById("search");
const backButton = document.getElementById("back-button");
const menuButton = document.getElementById("menu-button");
const drawerOverlay = document.getElementById("drawer-overlay");
let toc = null;
let currentTarget = "#00---indice";

function b64ToBytes(value) {
  const bin = atob(value);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}

async function deriveKey(password, salt, iterations) {
  const baseKey = await crypto.subtle.importKey(
    "raw",
    new TextEncoder().encode(password),
    "PBKDF2",
    false,
    ["deriveKey"]
  );
  return crypto.subtle.deriveKey(
    { name: "PBKDF2", salt, iterations, hash: "SHA-256" },
    baseKey,
    { name: "AES-GCM", length: 256 },
    false,
    ["decrypt"]
  );
}

async function unlock(password) {
  const salt = b64ToBytes(ENCRYPTED_PAYLOAD.salt);
  const nonce = b64ToBytes(ENCRYPTED_PAYLOAD.nonce);
  const ciphertext = b64ToBytes(ENCRYPTED_PAYLOAD.ciphertext);
  const key = await deriveKey(password, salt, ENCRYPTED_PAYLOAD.iterations);
  const plain = await crypto.subtle.decrypt({ name: "AES-GCM", iv: nonce }, key, ciphertext);
  return new TextDecoder().decode(plain);
}

function closeMenu() {
  document.body.classList.remove("menu-open");
  menuButton.setAttribute("aria-expanded", "false");
  drawerOverlay.hidden = true;
}

function openMenu() {
  document.body.classList.add("menu-open");
  menuButton.setAttribute("aria-expanded", "true");
  drawerOverlay.hidden = false;
}

function setActiveNav(noteId) {
  document.querySelectorAll(".toc a").forEach((link) => {
    link.classList.toggle("active", link.getAttribute("href") === `#${noteId}`);
  });
}

function hashId(hash) {
  const raw = (hash || "").replace(/^#/, "");
  try {
    return decodeURIComponent(raw);
  } catch (error) {
    return raw;
  }
}

function targetNote(hash) {
  const fallback = document.querySelector(".note");
  if (!hash || hash === "#") return fallback;
  const id = hashId(hash);
  const target = document.getElementById(id);
  if (!target) return fallback;
  return target.classList.contains("note") ? target : target.closest(".note") || fallback;
}

function showTarget(hash, shouldScroll = true) {
  const note = targetNote(hash);
  if (!note) return;
  currentTarget = hash && hash !== "#" ? hash : `#${note.id}`;
  document.querySelectorAll(".note").forEach((item) => {
    item.hidden = item !== note;
  });
  setActiveNav(note.id);
  if (!shouldScroll) return;
  const exact = document.getElementById(hashId(currentTarget));
  window.setTimeout(() => {
    (exact || note).scrollIntoView({ block: "start" });
  }, 0);
}

function navigateTo(hash) {
  const next = hash || "#00---indice";
  if (location.hash !== next) history.pushState(null, "", next);
  showTarget(next);
  closeMenu();
}

function initStudy() {
  toc = document.querySelector(".toc");
  if (toc) toc.id = "content-menu";
  document.querySelectorAll('#content a[href^="#"]').forEach((link) => {
    link.addEventListener("click", (event) => {
      event.preventDefault();
      navigateTo(link.getAttribute("href"));
    });
  });
  showTarget(location.hash || "#00---indice", false);
  window.scrollTo(0, 0);
}

form.addEventListener("submit", async (event) => {
  event.preventDefault();
  statusEl.textContent = "Verificando...";
  try {
    const html = await unlock(passwordInput.value);
    content.innerHTML = html;
    initStudy();
    gate.hidden = true;
    app.hidden = false;
    statusEl.textContent = "";
    window.scrollTo(0, 0);
  } catch (error) {
    statusEl.textContent = "Senha incorreta.";
    passwordInput.value = "";
    passwordInput.focus();
  }
});

backButton.addEventListener("click", () => {
  if (history.length > 1) history.back();
});

menuButton.addEventListener("click", () => {
  if (document.body.classList.contains("menu-open")) closeMenu();
  else openMenu();
});

drawerOverlay.addEventListener("click", closeMenu);

window.addEventListener("popstate", () => {
  showTarget(location.hash || currentTarget || "#00---indice");
  closeMenu();
});

search.addEventListener("input", () => {
  const term = search.value.trim().toLowerCase();
  if (!term) {
    showTarget(currentTarget, false);
    return;
  }
  document.querySelectorAll(".note").forEach((note) => {
    note.hidden = !note.textContent.toLowerCase().includes(term);
  });
});
